"""Lock: the charge tower is generated by one fixed cubic."""
import sympy as sp


def _T(M):
    return sp.Matrix(sp.BlockMatrix([[M, M], [M*M, M]]))


def test_charge_tower_from_fixed_cubic():
    """e_{n+1} = det(I - 2M + M^2 - M^3) over each rung; gives -11,-809,-18845089."""
    F = sp.Matrix([[1, 1], [1, 0]])
    M = F
    expected = [-11, -809, -18845089]
    for k in range(3):
        I = sp.eye(M.shape[0])
        e_next = (I - 2*M + M*M - M*M*M).det()
        assert e_next == (I.__class__(sp.eye(_T(M).shape[0])) - _T(M)).det()  # = det(I-M_{n+1})
        assert e_next == expected[k]
        M = _T(M)


def test_generating_cubic_disc_minus23():
    x = sp.Symbol('x')
    assert sp.discriminant(x**3 - x**2 + 2*x - 1, x) == -23
